import yaml from "js-yaml";

type FrontmatterRecord = Record<string, unknown>;

export type ExtractedYamlFrontmatter = {
  hasFrontmatter: boolean;
  frontmatter: FrontmatterRecord;
  rawFrontmatter: string;
  body: string;
  bodyStartLine: number;
  parseError: string | null;
};

function isPlainObject(value: unknown): value is FrontmatterRecord {
  return value != null && typeof value === "object" && !Array.isArray(value);
}

function normalizeSource(source: unknown) {
  return String(source || "").replace(/\r\n/g, "\n");
}

export function extractYamlFrontmatter(source: unknown): ExtractedYamlFrontmatter {
  const text = normalizeSource(source);
  const lines = text.split("\n");

  if (!lines.length || lines[0].trim() !== "---") {
    return {
      hasFrontmatter: false,
      frontmatter: {},
      rawFrontmatter: "",
      body: text,
      bodyStartLine: 0,
      parseError: null,
    };
  }

  let delimiterLineIndex = -1;
  for (let index = 1; index < lines.length; index += 1) {
    const trimmed = lines[index].trim();
    if (trimmed === "---" || trimmed === "...") {
      delimiterLineIndex = index;
      break;
    }
  }

  if (delimiterLineIndex < 0) {
    return {
      hasFrontmatter: false,
      frontmatter: {},
      rawFrontmatter: "",
      body: text,
      bodyStartLine: 0,
      parseError: null,
    };
  }

  const rawFrontmatter = lines.slice(1, delimiterLineIndex).join("\n");
  const body = lines.slice(delimiterLineIndex + 1).join("\n");

  try {
    const parsed = rawFrontmatter.trim() ? yaml.load(rawFrontmatter) : {};
    return {
      hasFrontmatter: true,
      frontmatter: isPlainObject(parsed) ? parsed : {},
      rawFrontmatter,
      body,
      bodyStartLine: delimiterLineIndex + 1,
      parseError: null,
    };
  } catch (error) {
    return {
      hasFrontmatter: false,
      frontmatter: {},
      rawFrontmatter: "",
      body: text,
      bodyStartLine: 0,
      parseError: error instanceof Error ? error.message : "No se pudo parsear el frontmatter YAML.",
    };
  }
}

export function stringifyYamlFrontmatter(frontmatter: unknown) {
  if (!isPlainObject(frontmatter) || !Object.keys(frontmatter).length) {
    return "";
  }

  const dumped = yaml.dump(frontmatter, {
    lineWidth: 120,
    noRefs: true,
    sortKeys: false,
  }).trimEnd();

  if (!dumped) {
    return "";
  }

  return `---\n${dumped}\n---`;
}

export function buildMarkdownDocumentWithFrontmatter({
  frontmatter,
  body,
}: {
  frontmatter?: unknown;
  body?: string | null;
}) {
  const serializedFrontmatter = stringifyYamlFrontmatter(frontmatter);
  const normalizedBody = typeof body === "string" ? body.trim() : "";

  if (!serializedFrontmatter) {
    return normalizedBody ? `${normalizedBody}\n` : "";
  }

  if (!normalizedBody) {
    return `${serializedFrontmatter}\n`;
  }

  return `${serializedFrontmatter}\n\n${normalizedBody}\n`;
}
